import{_ as s,o as t,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"28. Transfer Of Business","description":"","frontmatter":{"title":"28. Transfer Of Business","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["preliminary"]},"headers":[],"relativePath":"ebas/mspp/employment/28-transfer-of-business.md","filePath":"ebas/mspp/employment/28-transfer-of-business.md"}'),r={name:"ebas/mspp/employment/28-transfer-of-business.md"};function o(i,e,m,p,h,l){return t(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_28-transfer-of-business" tabindex="-1">28. Transfer Of Business <a class="header-anchor" href="#_28-transfer-of-business" aria-label="Permalink to &quot;28. Transfer Of Business&quot;">​</a></h1><p><strong>a.</strong> Where a business is before or after the date of this Agreement transmitted from an Employer (in this clause called the transmittor) to another Employer (in this clause called the transmittee) and an Employee who at the time of such transmission was an Employee of the transmittor in that business becomes an Employee of the transmittee:</p><p><strong>(i)</strong> the continuity of the employment of the Employee shall be deemed not to have been broken by reason of such transmission; and</p><p><strong>(ii)</strong> the period of employment which the Employee has had with the transmittor or any prior transmittor shall be deemed to be service of the Employee with the transmittee.</p><p><strong>b.</strong> In this clause business includes trade, process, business or occupation and includes any part of any such business and transmission includes transfer, conveyance, assignment or succession whether by agreement or by operation of law and transmitted has a corresponding meaning.</p><p>Plain language terms: transmission of business.</p>',6)])])}const d=s(r,[["render",o]]);export{c as __pageData,d as default};
